  { name: "Minor Luck", effect_type: "Attack Bonus", power_level: 2, description: "Allows to get 10 instead of rolling the d20 for an attack roll (3/day)", name_es: "Suerte Menor", description_es: "Permite obtener 10 en lugar de tirar el d20 para una tirada de ataque (3/día)", categories: [weapon_category, gloves_category] },
  { name: "Divine Mattock", effect_type: "Attack Bonus", power_level: 2, description: "As an action, you can channel divine power to cast Move Earth or Fabricate. Once this property is used, it can’t be used again until the next dawn", name_es: "Azada Divina", description_es: "Como acción, puedes canalizar poder divino para lanzar Mover Tierra o Fabricar. Una vez usada esta propiedad, no puede volver a usarse hasta el siguiente amanecer", categories: [weapon_category, gloves_category] },
  { name: "Reforged", effect_type: "Attack Bonus", power_level: 2, description: "While holding this item, you have resistance to fire damage and are immune to exhaustion. Additionally, you have proficiency with smith’s tools and have advantage on all ability checks made using them", name_es: "Reforjado", description_es: "Mientras sostienes este objeto, tienes resistencia al daño de fuego e inmunidad al agotamiento. Además, tienes competencia con herramientas de herrero y ventaja en todas las pruebas de habilidad que las usen", categories: [weapon_category, gloves_category] },
  { name: "Smith’s Spells", effect_type: "Attack Bonus", power_level: 3, description: "While this item is on your person, you can use an action to cast one of the following spells (save DC 18): Animate Objects, Heat Metal, Fabricate, Magic Weapon, Mending, Shatter. Once you use the hammer to cast a spell, the spell can’t be cast again from it until the next dusk", name_es: "Conjuros del Herrero", description_es: "Mientras llevas este objeto, puedes usar una acción para lanzar uno de los siguientes conjuros (CD de salvación 18): Animar Objetos, Metal Candente, Fabricar, Arma Mágica, Reparar, Estallido. Una vez lanzado un conjuro, no puede volver a lanzarse hasta el siguiente anochecer", categories: [weapon_category, gloves_category] },
  { name: "Conjure Earth Elemental", effect_type: "Conjuration", power_level: 2, description: "If you are holding it, you can use your action to cast the Conjure Elemental spell from it, summoning an earth elemental. You can’t use this property again until the next dawn", name_es: "Convocar Elemental de Tierra", description_es: "Si lo estás sosteniendo, puedes usar tu acción para lanzar el conjuro Convocar Elemental, invocando un elemental de tierra. No puedes usar esta propiedad de nuevo hasta el siguiente amanecer", categories: [weapon_category, gloves_category, boots_category, bracelet_category] },
  { name: "Helpful Hand", effect_type: "Handling", power_level: 3, description: "As an action, you can use the bracelet to cast Bigby’s Hand as a 9th-level spell (spell attack bonus +13). When you cast the spell this way, the spell doesn’t require concentration. Once this property is used, it can’t be used again until the next dawn.", name_es: "Mano Útil", description_es: "Como acción, puedes usar el brazalete para lanzar la Mano de Bigby como conjuro de nivel 9 (bono de ataque de conjuro +13). Al lanzar el conjuro de esta manera, no requiere concentración. Una vez usada esta propiedad, no puede volver a usarse hasta el siguiente amanecer.", categories: [weapon_category, gloves_category, bracelet_category] },
  { name: "Dexterous Fingers", effect_type: "Handling", power_level: 1, description: "While wearing the bracelet, you can cast Mage Hand", name_es: "Dedos Diestros", description_es: "Mientras llevas el brazalete, puedes lanzar Mano de Mago", categories: [weapon_category, gloves_category, ring_category, amulet_category, shield_category, boots_category, wands_category, staff_category, armor_category, bracelet_category] },
  { name: "Sentient", effect_type: "Sentient", power_level: 4, description: "The item is a sentient chaotic evil artifact with an Intelligence of 21, a Wisdom of 24, and a Charisma of 24. It has hearing and darkvision out to 120 feet. It communicates telepathically with its wielder and can speak, read, and understand 3 languages", name_es: "Sintiente", description_es: "El objeto es un artefacto consciente de alineamiento caótico malvado con Inteligencia 21, Sabiduría 24 y Carisma 24. Tiene oído y visión en la oscuridad hasta 36 metros. Se comunica telepáticamente con su portador y puede hablar, leer y entender 3 idiomas", categories: [weapon_category, gloves_category, bracelet_category] },
  { name: "Mithril Alloy", effect_type: "Material", power_level: 3, description: "Damage magical creatures, +1 to Attack, +1 to Damage, +1 to AC, +1 to Initiative Rolls, cannot be destroyed", name_es: "Aleación de Mithril", description_es: "Daña criaturas mágicas, +1 al Ataque, +1 al Daño, +1 a la CA, +1 a las tiradas de Iniciativa, no puede ser destruido", categories: [weapon_category, armor_category, shield_category] },
  { name: "Mithril", effect_type: "Material", power_level: 5, description: "Damage magical creatures, +3 to Attack, +3 to Damage, +3 to AC, +3 to Initiative Rolls, cannot be destroyed", name_es: "Mithril", description_es: "Daña criaturas mágicas, +3 al Ataque, +3 al Daño, +3 a la CA, +3 a las tiradas de Iniciativa, no puede ser destruido", categories: [weapon_category, armor_category, shield_category] },
  { name: "Lightweight", effect_type: "Material", power_level: 1, description: "The object is extraordinarily light, reducing the weight by half", name_es: "Ligero", description_es: "El objeto es extraordinariamente ligero, reduciendo su peso a la mitad", categories: [weapon_category, shield_category, armor_category] },
