  { name: "Unyielding Defense", effect_type: "Material", power_level: 2, description: "While wielding this item, you gain +1 to AC", name_es: "Defensa Inquebrantable", description_es: "Mientras empuñas este objeto, obtienes +1 a la CA", categories: [weapon_category, shield_category] },
