  { name: "Precise Strike", effect_type: "Material", power_level: 2, description: "Your critical hit range increases by 1", name_es: "Golpe Preciso", description_es: "Tu rango de golpe crítico aumenta en 1", categories: [weapon_category] },
  { name: "Mithril Resilience", effect_type: "Material", power_level: 1, description: "The item is nearly indestructible, granting resistance to any attempt to break or damage it", name_es: "Resistencia de Mithril", description_es: "El objeto es casi indestructible, otorgando resistencia a cualquier intento de romperlo o dañarlo", categories: [weapon_category] },
  { name: "Spell Channeling", effect_type: "Material", power_level: 2, description: "The item can be used as a focus for spellcasting, granting +1 to spell attack rolls", name_es: "Canalización de Conjuros", description_es: "El objeto puede usarse como foco para lanzar conjuros, otorgando +1 a las tiradas de ataque de conjuro", categories: [weapon_category, staff_category] },
  { name: "Finesse Mastery", effect_type: "Material", power_level: 3, description: "The item gains the Finesse property, allowing you to use Dexterity for attack and damage rolls", name_es: "Maestría en Finura", description_es: "El objeto adquiere la propiedad Sutileza, permitiéndote usar Destreza para las tiradas de ataque y daño", categories: [weapon_category] },
  { name: "Unbreakable Will", effect_type: "Material", power_level: 2, description: "While holding this item, you gain advantage on saving throws against being charmed or frightened", name_es: "Voluntad Inquebrantable", description_es: "Mientras sostienes este objeto, obtienes ventaja en las tiradas de salvación contra ser hechizado o asustado", categories: [weapon_category] },
