	{ name: "Potion of Fire Resistance", effect_type: "Resistance", power_level: 2, description: "Grants resistance to fire damage for 1 hour", name_es: "Poción de Resistencia al Fuego", description_es: "Otorga resistencia al daño de fuego durante 1 hora", categories: [potions_category] },
	{ name: "Potion of True Sight", effect_type: "Sight", power_level: 2, description: "Grants the ability to see invisible creatures and objects, and see into the Ethereal Plane for 1 hour", name_es: "Poción de Visión Verdadera", description_es: "Otorga la capacidad de ver criaturas y objetos invisibles, y ver el Plano Etéreo durante 1 hora", categories: [potions_category] },
	{ name: "Potion of Healing", effect_type: "Healing", power_level: 1, description: "Restores 2d4 + 2 hit points", name_es: "Poción de Curación", description_es: "Restaura 2d4 + 2 puntos de golpe", categories: [potions_category] },
	{ name: "Potion of Flight", effect_type: "Flight", power_level: 3, description: "Grants a flying speed equal to your walking speed for 10 minutes", name_es: "Poción de Vuelo", description_es: "Otorga una velocidad de vuelo igual a tu velocidad de caminar durante 10 minutos", categories: [potions_category] },
	{ name: "Potion of Invisibility", effect_type: "Stealth", power_level: 2, description: "Grants invisibility for 1 hour, ending if you attack or cast a spell", name_es: "Poción de Invisibilidad", description_es: "Otorga invisibilidad durante 1 hora, finalizando si atacas o lanzas un conjuro", categories: [potions_category] },
	{ name: "Potion of Vitality", effect_type: "Healing", power_level: 2, description: "Removes all exhaustion, cures any disease or poison, and restores maximum hit points for 24 hours", name_es: "Poción de Vitalidad", description_es: "Elimina todo el agotamiento, cura cualquier enfermedad o veneno, y restaura los puntos de golpe máximos durante 24 horas", categories: [potions_category] },

	{ name: "Climbing Speed", effect_type: "Climbing", power_level: 2, description: "Grant a climbing speed equal to your walking speed for 1 hour", name_es: "Velocidad de Escalada", description_es: "Otorga una velocidad de escalada igual a tu velocidad de caminar durante 1 hora", categories: [boots_category, cloak_category, trinkets_category] },
	{ name: "Power Knockback", effect_type: "Proning", power_level: 3, description: "On hit, the target must succeed on a Strength saving throw or be knocked prone", name_es: "Empuje Poderoso", description_es: "Al golpear, el objetivo debe superar una tirada de salvación de Fuerza o caer derribado", categories: [ammunition_category, weapon_category] },
	{ name: "Saddle of Secure Riding", effect_type: "Equilibrium", power_level: 2, description: "Prevents the rider from being dismounted against their will", name_es: "Silla de Montura Segura", description_es: "Impide que el jinete sea desmontado contra su voluntad", categories: [trinkets_category] },
	{ name: "Ring of Invisibility", effect_type: "Stealth", power_level: 3, description: "You become invisible until the ring is removed, or you attack or cast a spell", name_es: "Anillo de Invisibilidad", description_es: "Te vuelves invisible hasta que el anillo se retire, o ataques o lances un conjuro", categories: [ring_category] },
	{ name: "Naked Bonus", effect_type: "Defensive", power_level: 4, description: "+2 bonus to AC without armor nor shield", name_es: "Bono sin Armadura", description_es: "+2 de bono a la CA sin armadura ni escudo", categories: [ring_category, amulet_category] },

	{ name: "Breathing Cap", effect_type: "Breathing", power_level: 3, description: "Allows you to breathe normally underwater", name_es: "Capucha de Respiración", description_es: "Permite respirar con normalidad bajo el agua", categories: [helm_category, trinkets_category, cloak_category] },
	{ name: "Horn of Hearing", effect_type: "Loudness", power_level: 2, description: "Suppresses the effects of the deafened condition on you", name_es: "Cuerno de la Audición", description_es: "Suprime los efectos de la condición ensordecido sobre ti", categories: [trinkets_category] },
	{ name: "Traveler's Clothes Repair", effect_type: "Durability", power_level: 1, description: "Magically mends itself to counteract daily wear and tear", name_es: "Reparación de Ropa de Viajero", description_es: "Se repara mágicamente para contrarrestar el desgaste diario", categories: [cloak_category, boots_category, trinkets_category] },
	{ name: "Glowing Eyes Helm", effect_type: "Glow", power_level: 2, description: "Makes your eyes glow red with a fearsome intensity", name_es: "Yelmo de Ojos Brillantes", description_es: "Hace que tus ojos brillen en rojo con una intensidad aterradora", categories: [helm_category, armor_category, trinkets_category] },

  # ═══════════════════════════════════════════
  # CREATIVE & FUN EFFECTS
  # ═══════════════════════════════════════════

  # Luck
  { name: "Gambler's Grace", effect_type: "Luck", power_level: 1, description: "Once per day, you may reroll any d20 and keep the second result. The item whispers 'double or nothing' each time.", name_es: "Gracia del Jugador", description_es: "Una vez por día, puedes volver a tirar cualquier d20 y quedarte con el segundo resultado. El objeto susurra 'doble o nada' cada vez.", categories: [ring_category, amulet_category, trinkets_category, gem_category] },
  { name: "Fool's Fortune", effect_type: "Luck", power_level: 2, description: "When you roll a natural 1, you may treat it as a natural 20 once per long rest. The item giggles maniacally when triggered.", name_es: "Fortuna del Tonto", description_es: "Cuando sacas un 1 natural, puedes tratarlo como un 20 natural una vez por descanso largo. El objeto ríe maníacamente cuando se activa.", categories: [ring_category, amulet_category, trinkets_category] },
  { name: "Lucky Coin Flip", effect_type: "Luck", power_level: 1, description: "Summon a spectral coin. Heads grants advantage on your next roll; tails gives disadvantage. Fate loves a gambler.", name_es: "Lanzamiento de Moneda Afortunada", description_es: "Convoca una moneda espectral. Cara otorga ventaja en tu siguiente tirada; cruz da desventaja. El destino ama a los jugadores.", categories: [trinkets_category, ring_category, gem_category] },
  { name: "Jinxbreaker", effect_type: "Luck", power_level: 3, description: "Negate one critical hit against you per day. The attack still hits but deals normal damage instead.", name_es: "Rompemaldiciones", description_es: "Niega un golpe crítico contra ti por día. El ataque aún impacta pero inflige daño normal en su lugar.", categories: [amulet_category, ring_category, shield_category, armor_category] },

  # Summoning
  { name: "Pocket Familiar", effect_type: "Summoning", power_level: 1, description: "Summon a tiny spectral animal companion (cat, owl, or toad). It can scout 60 ft and relay what it sees telepathically.", name_es: "Familiar de Bolsillo", description_es: "Invoca un pequeño animal espectral acompañante (gato, búho o sapo). Puede explorar hasta 18 metros y transmitir telepáticamente lo que ve.", categories: [ring_category, amulet_category, trinkets_category, wands_category] },
  { name: "Swarm Caller", effect_type: "Summoning", power_level: 3, description: "Once per day, summon a swarm of spectral insects that harass enemies in a 15-ft area, imposing disadvantage on concentration checks.", name_es: "Llamador de Enjambres", description_es: "Una vez por día, invoca un enjambre de insectos espectrales que acosan a los enemigos en un área de 4,5 metros, imponiendo desventaja en las pruebas de concentración.", categories: [staff_category, wands_category, ring_category] },
  { name: "Shadow Servant", effect_type: "Summoning", power_level: 2, description: "Summon an obedient shadow that can carry up to 30 lbs, open doors, and perform simple tasks. Lasts 1 hour.", name_es: "Sirviente de Sombra", description_es: "Invoca una sombra obediente que puede cargar hasta 13,6 kg, abrir puertas y realizar tareas simples. Dura 1 hora.", categories: [ring_category, amulet_category, cloak_category] },
  { name: "Phantasmal Steed", effect_type: "Summoning", power_level: 3, description: "Summon a ghostly horse with 60 ft speed and the ability to gallop across water. Lasts 1 hour, once per long rest.", name_es: "Corcel Fantasmal", description_es: "Invoca un caballo fantasmal con velocidad de 18 metros y la capacidad de galopar sobre el agua. Dura 1 hora, una vez por descanso largo.", categories: [boots_category, ring_category, amulet_category] },

  # Control
  { name: "Gravity Well", effect_type: "Control", power_level: 3, description: "Once per day, create a 20-ft zone of intense gravity. Creatures entering must succeed on a STR save or be restrained for 1 round.", name_es: "Pozo de Gravedad", description_es: "Una vez por día, crea una zona de gravedad intensa de 6 metros. Las criaturas que entren deben superar una tirada de salvación de Fuerza o quedar retenidas durante 1 turno.", categories: [staff_category, wands_category, ring_category, gem_category] },
  { name: "Puppet Strings", effect_type: "Control", power_level: 4, description: "As an action, force one humanoid within 30 ft to make a WIS save or be compelled to move 15 ft in a direction you choose.", name_es: "Hilos de Marioneta", description_es: "Como acción, obliga a un humanoide a 9 metros a hacer una tirada de salvación de Sabiduría o ser compelido a moverse 4,5 metros en una dirección que elijas.", categories: [gloves_category, ring_category, wands_category] },
  { name: "Terrain Sculptor", effect_type: "Control", power_level: 2, description: "Shape a 10-ft square of earth, stone, or ice into difficult terrain or smooth ground. The reshaping lasts 10 minutes.", name_es: "Escultor del Terreno", description_es: "Moldea un cuadrado de 3 metros de tierra, piedra o hielo en terreno difícil o suelo liso. El remodelado dura 10 minutos.", categories: [staff_category, wands_category, gloves_category] },

  # Minding
  { name: "Thought Echo", effect_type: "Minding", power_level: 2, description: "Read the surface thoughts of one creature within 30 ft for 1 minute, once per day. They feel a faint tickle but don't know the source.", name_es: "Eco de Pensamientos", description_es: "Lee los pensamientos superficiales de una criatura a 9 metros durante 1 minuto, una vez por día. Sienten un ligero cosquilleo pero no conocen la fuente.", categories: [helm_category, amulet_category, ring_category] },
  { name: "Dream Weaver", effect_type: "Minding", power_level: 3, description: "Send a message to a sleeping creature you know by name, anywhere on the same plane. They experience it as a vivid dream.", name_es: "Tejedor de Sueños", description_es: "Envía un mensaje a una criatura dormida que conoces por nombre, en cualquier lugar del mismo plano. Lo experimenta como un sueño vívido.", categories: [amulet_category, ring_category, gem_category, trinkets_category] },
  { name: "Psychic Scream", effect_type: "Minding", power_level: 4, description: "Release a mental blast in a 15-ft cone. Each creature must succeed on an INT save or take 3d6 psychic damage and be stunned until end of their next turn. Once per long rest.", name_es: "Grito Psíquico", description_es: "Libera una explosión mental en un cono de 4,5 metros. Cada criatura debe superar una tirada de salvación de Inteligencia o recibir 3d6 de daño psíquico y quedar aturdida hasta el final de su siguiente turno. Una vez por descanso largo.", categories: [helm_category, staff_category, wands_category] },

  # Vision
  { name: "Eagle Eye", effect_type: "Vision", power_level: 1, description: "You can see clearly up to 1 mile as if it were only 30 feet away. Works like a built-in spyglass.", name_es: "Ojo de Águila", description_es: "Puedes ver con claridad hasta 1,6 km como si estuvieran a solo 9 metros. Funciona como un catalejo incorporado.", categories: [helm_category, ring_category, amulet_category, trinkets_category] },
  { name: "Spectral Sight", effect_type: "Vision", power_level: 3, description: "See into the Ethereal Plane within 60 ft. Invisible creatures and objects appear as faint translucent silhouettes.", name_es: "Visión Espectral", description_es: "Ve el Plano Etéreo en un radio de 18 metros. Las criaturas y objetos invisibles aparecen como tenues siluetas translúcidas.", categories: [helm_category, ring_category, gem_category] },
  { name: "Memory Lens", effect_type: "Vision", power_level: 2, description: "Touch an object to see a 30-second vision of the last significant event that occurred near it. Once per short rest.", name_es: "Lente de Memoria", description_es: "Toca un objeto para ver una visión de 30 segundos del último evento significativo que ocurrió cerca de él. Una vez por descanso corto.", categories: [ring_category, gem_category, trinkets_category] },

  # Flight
  { name: "Windrunner", effect_type: "Flight", power_level: 2, description: "Gain a flying speed of 30 ft for 1 minute, once per day. A trail of glowing feathers marks your path.", name_es: "Corredor del Viento", description_es: "Obtén una velocidad de vuelo de 9 metros durante 1 minuto, una vez por día. Un rastro de plumas brillantes marca tu camino.", categories: [boots_category, cloak_category, ring_category] },
  { name: "Levitation Field", effect_type: "Flight", power_level: 1, description: "Hover up to 5 ft above the ground at will. You ignore ground-based traps and difficult terrain but can't ascend higher.", name_es: "Campo de Levitación", description_es: "Flota hasta 1,5 metros sobre el suelo a voluntad. Ignoras las trampas del suelo y el terreno difícil pero no puedes ascender más.", categories: [boots_category, ring_category, amulet_category] },
  { name: "Storm Rider", effect_type: "Flight", power_level: 4, description: "Gain a flying speed of 60 ft for 10 minutes, once per long rest. Lightning crackles around you, dealing 1d4 to creatures you fly past.", name_es: "Jinete de Tormenta", description_es: "Obtén una velocidad de vuelo de 18 metros durante 10 minutos, una vez por descanso largo. El relámpago crepita a tu alrededor, infligiendo 1d4 a las criaturas que sobrevuelas.", categories: [cloak_category, boots_category, staff_category] },

  # Speed
  { name: "Blink Step", effect_type: "Speed", power_level: 2, description: "As a bonus action, teleport up to 15 ft to an unoccupied space you can see. You leave a puff of smoke behind. 3 uses per long rest.", name_es: "Paso Parpadeante", description_es: "Como acción adicional, teleportate hasta 4,5 metros a un espacio desocupado que puedas ver. Dejas una nube de humo detrás. 3 usos por descanso largo.", categories: [boots_category, ring_category, amulet_category] },
  { name: "Afterimage", effect_type: "Speed", power_level: 3, description: "When you take the Dash action, leave a translucent copy of yourself behind. The copy lasts 1 round and enemies have disadvantage on attacks against you while it exists.", name_es: "Imagen Residual", description_es: "Cuando realizas la acción Correr, dejas atrás una copia translúcida de ti mismo. La copia dura 1 turno y los enemigos tienen desventaja en los ataques contra ti mientras existe.", categories: [boots_category, cloak_category, ring_category] },
  { name: "Quicksilver Reflexes", effect_type: "Speed", power_level: 2, description: "You can take reactions twice per round instead of once. Your movements shimmer with a mercurial glow.", name_es: "Reflejos de Mercurio", description_es: "Puedes realizar reacciones dos veces por turno en vez de una. Tus movimientos brillan con un resplandor mercurial.", categories: [gloves_category, boots_category, bracelet_category] },

  # Healing
  { name: "Life Leech", effect_type: "Healing", power_level: 2, description: "On a successful melee hit, regain HP equal to half the damage dealt. Works once per short rest. The item pulses with a crimson glow.", name_es: "Drenaje de Vida", description_es: "Tras un golpe cuerpo a cuerpo exitoso, recupera PG iguales a la mitad del daño infligido. Funciona una vez por descanso corto. El objeto pulsa con un brillo carmesí.", categories: [weapon_category, gloves_category] },
  { name: "Phoenix Tear", effect_type: "Healing", power_level: 4, description: "When you drop to 0 HP, immediately regain 3d8+5 HP and stand up. This destroys the tear. A burst of golden fire erupts around you.", name_es: "Lágrima de Fénix", description_es: "Cuando caes a 0 PG, recuperas inmediatamente 3d8+5 PG y te levantas. Esto destruye la lágrima. Un estallido de fuego dorado erupciona a tu alrededor.", categories: [amulet_category, gem_category, ring_category] },
  { name: "Sanguine Bond", effect_type: "Healing", power_level: 3, description: "As an action, sacrifice up to 20 of your HP to heal an ally within touch range for the same amount plus 1d8. Once per long rest.", name_es: "Vínculo Sanguíneo", description_es: "Como acción, sacrifica hasta 20 PG para curar a un aliado al alcance de toque por la misma cantidad más 1d8. Una vez por descanso largo.", categories: [ring_category, amulet_category, gloves_category] },

  # Protection
  { name: "Mirror Ward", effect_type: "Protection", power_level: 3, description: "Once per day, reflect the next spell of 3rd level or lower cast at you back at the caster, using their own spell attack or save DC.", name_es: "Protección Espejo", description_es: "Una vez por día, refleja el siguiente conjuro de nivel 3 o inferior lanzado contra ti de vuelta al lanzador, usando su propio bono de ataque de conjuro o CD de salvación.", categories: [shield_category, armor_category, amulet_category] },
  { name: "Death's Denial", effect_type: "Protection", power_level: 5, description: "Once per week, when you would be killed, time freezes for 6 seconds. You are stabilized at 1 HP and teleported 30 ft in a random direction.", name_es: "Negación de la Muerte", description_es: "Una vez por semana, cuando serías asesinado, el tiempo se congela durante 6 segundos. Quedas estabilizado con 1 PG y te teleportas 9 metros en una dirección aleatoria.", categories: [amulet_category, ring_category, armor_category] },
  { name: "Absorb Elements", effect_type: "Protection", power_level: 2, description: "As a reaction when hit by elemental damage, gain resistance to that damage type until start of your next turn. 3 uses per long rest.", name_es: "Absorber Elementos", description_es: "Como reacción al recibir daño elemental, obtén resistencia a ese tipo de daño hasta el inicio de tu siguiente turno. 3 usos por descanso largo.", categories: [shield_category, armor_category, ring_category, bracelet_category] },

  # Frosting
  { name: "Glacial Prison", effect_type: "Frosting", power_level: 3, description: "On a critical hit, the target is encased in ice and restrained until they succeed on a STR save at the start of their turn.", name_es: "Prisión Glacial", description_es: "En un golpe crítico, el objetivo queda encapsulado en hielo y retenido hasta que supere una tirada de salvación de Fuerza al inicio de su turno.", categories: [weapon_category, ammunition_category, staff_category] },
  { name: "Winter's Breath", effect_type: "Frosting", power_level: 2, description: "As an action, exhale a 15-ft cone of frost. Creatures take 2d6 cold damage and their speed is halved for 1 round. 2 uses per day.", name_es: "Aliento de Invierno", description_es: "Como acción, exhala un cono de escarcha de 4,5 metros. Las criaturas reciben 2d6 de daño de frío y su velocidad se reduce a la mitad durante 1 turno. 2 usos por día.", categories: [helm_category, amulet_category, ring_category] },

  # Lightning
  { name: "Chain Lightning Strike", effect_type: "Lightning", power_level: 3, description: "On a hit, lightning arcs to up to 2 additional creatures within 15 ft, dealing 1d6 lightning damage to each. Once per short rest.", name_es: "Golpe de Relámpago en Cadena", description_es: "Al golpear, el relámpago se ramifica a hasta 2 criaturas adicionales a 4,5 metros, infligiendo 1d6 de daño de relámpago a cada una. Una vez por descanso corto.", categories: [weapon_category, staff_category, wands_category] },
  { name: "Thunderclap", effect_type: "Lightning", power_level: 2, description: "As an action, slam the item to create a thunderclap in a 10-ft radius. Creatures must make a CON save or be deafened and pushed 5 ft. 3 uses per day.", name_es: "Truenazo", description_es: "Como acción, golpea el objeto para crear un truenazo en un radio de 3 metros. Las criaturas deben hacer una tirada de salvación de Constitución o quedar ensordecidas y empujadas 1,5 metros. 3 usos por día.", categories: [weapon_category, shield_category, staff_category] },

  # Utility
  { name: "Mood Ring", effect_type: "Utility", power_level: 1, description: "Changes color based on the emotional state of the nearest creature. Red = angry, blue = sad, green = calm, gold = happy.", name_es: "Anillo del Humor", description_es: "Cambia de color según el estado emocional de la criatura más cercana. Rojo = enojado, azul = triste, verde = tranquilo, dorado = feliz.", categories: [ring_category, trinkets_category] },
  { name: "Portable Campfire", effect_type: "Utility", power_level: 1, description: "Summon a small magical campfire that provides warmth, light (20 ft), and cooks food without fuel. Lasts 8 hours.", name_es: "Fogata Portátil", description_es: "Invoca una pequeña fogata mágica que proporciona calor, luz (6 metros) y cocina alimentos sin combustible. Dura 8 horas.", categories: [trinkets_category, gem_category] },
  { name: "Bag of Holding (Mini)", effect_type: "Utility", power_level: 2, description: "This tiny pouch can hold up to 50 lbs of items in an extradimensional space no larger than 2 cubic feet.", name_es: "Bolsa de Contención (Mini)", description_es: "Esta pequeña bolsa puede contener hasta 22,7 kg de objetos en un espacio extradimensional de no más de 0,06 metros cúbicos.", categories: [trinkets_category] },
  { name: "Bardic Echo", effect_type: "Utility", power_level: 1, description: "This item can record up to 1 minute of sound and play it back at will. Perfect for dramatic entrances.", name_es: "Eco Bárdico", description_es: "Este objeto puede grabar hasta 1 minuto de sonido y reproducirlo a voluntad. Perfecto para entradas dramáticas.", categories: [trinkets_category, gem_category] },
  { name: "Unseen Butler", effect_type: "Utility", power_level: 2, description: "Summon an invisible servant that sets up camp, cleans equipment, and serves meals. It cannot fight or carry more than 10 lbs.", name_es: "Mayordomo Invisible", description_es: "Invoca un sirviente invisible que monta el campamento, limpia el equipo y sirve comidas. No puede pelear ni cargar más de 4,5 kg.", categories: [ring_category, trinkets_category] },
  { name: "Translator's Tongue", effect_type: "Understanding", power_level: 2, description: "Understand and speak any language for 10 minutes, 3 times per day. Your words have a faint magical echo.", name_es: "Lengua del Traductor", description_es: "Entiende y habla cualquier idioma durante 10 minutos, 3 veces por día. Tus palabras tienen un tenue eco mágico.", categories: [amulet_category, ring_category, helm_category] },
  { name: "Diplomat's Charm", effect_type: "Utility", power_level: 2, description: "Gain advantage on Persuasion checks for 10 minutes, once per day. A faint golden aura surrounds you when active.", name_es: "Encanto del Diplomático", description_es: "Obtén ventaja en las pruebas de Persuasión durante 10 minutos, una vez por día. Un tenue aura dorada te rodea cuando está activo.", categories: [amulet_category, ring_category, gem_category, bracelet_category] },
  { name: "Chrono Pocket Watch", effect_type: "Utility", power_level: 3, description: "Once per day, rewind time by 6 seconds. You return to where you were and can take your last turn differently.", name_es: "Reloj Crono de Bolsillo", description_es: "Una vez por día, rebobina el tiempo 6 segundos. Vuelves a donde estabas y puedes tomar tu último turno de manera diferente.", categories: [trinkets_category, ring_category, gem_category] },

  # Stealth
  { name: "Smoke Bomb", effect_type: "Stealth", power_level: 1, description: "As a bonus action, throw a smoke bomb creating a 10-ft radius of heavy obscurement that lasts 1 round. 3 uses per day.", name_es: "Bomba de Humo", description_es: "Como acción adicional, lanza una bomba de humo creando un radio de 3 metros de oscurecimiento total que dura 1 turno. 3 usos por día.", categories: [trinkets_category, gloves_category, cloak_category] },
  { name: "Chameleon Skin", effect_type: "Stealth", power_level: 2, description: "While motionless, you become nearly invisible, gaining advantage on Stealth checks and +5 to your passive Stealth.", name_es: "Piel de Camaleón", description_es: "Mientras estás inmóvil, te vuelves casi invisible, obteniendo ventaja en las pruebas de Sigilo y +5 a tu Sigilo pasivo.", categories: [cloak_category, armor_category, ring_category] },
  { name: "Silence Aura", effect_type: "Stealth", power_level: 2, description: "Create a 5-ft sphere of silence around you for 1 minute, 2 times per day. No sound enters or leaves the sphere.", name_es: "Aura de Silencio", description_es: "Crea una esfera de silencio de 1,5 metros a tu alrededor durante 1 minuto, 2 veces por día. Ningún sonido entra o sale de la esfera.", categories: [boots_category, cloak_category, amulet_category] },

  # Scrolls & Elixirs
  { name: "Scroll of Doppelganger", effect_type: "Control", power_level: 3, description: "Create an illusory double of yourself that mimics your actions 30 ft away. Lasts 1 minute. Enemies must guess which is real.", name_es: "Pergamino del Doble", description_es: "Crea un doble ilusorio tuyo que imita tus acciones a 9 metros. Dura 1 minuto. Los enemigos deben adivinar cuál es real.", categories: [wands_category] },
  { name: "Elixir of Iron Will", effect_type: "Resistance", power_level: 2, description: "Gain advantage on all Wisdom saving throws for 1 hour. Your eyes glow with a faint silver light.", name_es: "Elixir de Voluntad de Hierro", description_es: "Obtén ventaja en todas las tiradas de salvación de Sabiduría durante 1 hora. Tus ojos brillan con una tenue luz plateada.", categories: [potions_category] },
  { name: "Elixir of Giant's Grasp", effect_type: "Enhance", power_level: 2, description: "Your hands grow to twice their size for 10 minutes. Grapple checks gain advantage and unarmed strikes deal 1d8.", name_es: "Elixir del Agarre del Gigante", description_es: "Tus manos crecen al doble de su tamaño durante 10 minutos. Las pruebas de agarrar obtienen ventaja y los golpes desarmados infligen 1d8.", categories: [potions_category] },
